const items = $input.all();
const courses = items.filter(item => item.json.id !== 1);
return courses.map(item => ({ json: item.json }));

const SUPPORTED_MIMES = [
  'application/pdf',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/vnd.openxmlformats-officedocument.presentationml.presentation',
  'text/markdown'
];

const courseItem = $('Loop Courses').item;
const courseId = courseItem.json.id;
const rawShortname = courseItem.json.shortname || `course-${courseId}`;
function slugify(s, id) {
  const slug = s
    .normalize('NFD').replace(/\p{M}/gu, '')
    .toLowerCase()
    .replace(/[^0-9a-z_-]+/g, '-')
    .replace(/-{2,}/g, '-')
    .replace(/^-+|-+$/g, '')
    .substring(0, 50);
  return slug || `course-${id}`;
}
const namespace = slugify(rawShortname, courseId);

const response = $input.first();
const sections = response.json.body || response.json;

// Safety: if Moodle returned an error or unexpected format, abort with _moodleError flag.
// Returning files:[] would cause Dedup&Diff to mark ALL stored files as deleted — catastrophic.
if (!Array.isArray(sections)) {
  const raw = JSON.stringify(sections).slice(0, 200);
  return [{ json: { _moodleError: true, errorDetail: raw, courseId, namespace, files: [] } }];
}

const files = [];
for (const section of sections) {
  if (!section.modules) continue;
  for (const mod of section.modules) {
    if (!mod.contents) continue;
    for (const content of mod.contents) {
      if (content.type !== 'file') continue;
      if (!SUPPORTED_MIMES.includes(content.mimetype)) continue;
      files.push({
        fileurl: content.fileurl,
        filename: content.filename,
        uniqueFilename: `mod${mod.id}_${content.filename}`,
        filesize: content.filesize,
        timemodified: content.timemodified,
        mimetype: content.mimetype,
        moduleId: mod.id,
        moduleName: mod.name,
        sectionName: section.name,
        courseId,
        namespace
      });
    }
  }
}

return [{ json: { courseId, namespace, files } }];

const fs = require('fs');
const STATE_FILE = $env.STATE_FILE_PATH || '/home/node/.n8n/moodle-ingest-state.json';
function readState() { try { return JSON.parse(fs.readFileSync(STATE_FILE, 'utf8')); } catch(e) { return { courseFiles: {} }; } }

const input = $input.first().json;
const namespace = input.namespace;
const courseId = input.courseId;

// Abort if Moodle returned an error — never compute deletions from an empty file list.
if (input._moodleError) {
  return [{ json: { courseId, namespace, toIngest: [], toDelete: [], unchanged: [], _moodleError: true, errorDetail: input.errorDetail, summary: { new: 0, updated: 0, removed: 0, unchanged: 0 } } }];
}

const state = readState();
if (!state.courseFiles) state.courseFiles = {};

const currentFiles = input.files || [];
const storedFiles = state.courseFiles[namespace] || {};

// Safety: if Moodle returned a valid but empty file list while we have stored files,
// something is wrong (course temporarily inaccessible, WS token issue, etc.).
// Skip ALL deletions to avoid wiping Qdrant data on a false signal.
const DELETION_SAFETY_THRESHOLD = 3;
if (currentFiles.length === 0 && Object.keys(storedFiles).length >= DELETION_SAFETY_THRESHOLD) {
  return [{ json: { courseId, namespace, toIngest: [], toDelete: [], unchanged: [], _emptyCourseSafe: true, summary: { new: 0, updated: 0, removed: 0, unchanged: Object.keys(storedFiles).length } } }];
}

const toIngest = [];
const toDelete = [];
const unchanged = [];
const currentFileUrls = new Set(currentFiles.map(f => f.fileurl));

for (const file of currentFiles) {
  const stored = storedFiles[file.fileurl];
  if (!stored) {
    toIngest.push({ ...file, action: 'new' });
  } else if (stored.timemodified !== file.timemodified) {
    toIngest.push({ ...file, action: 'updated', old_document_id: stored.document_id });
  } else {
    unchanged.push({ ...file, action: 'unchanged' });
  }
}

for (const [fileurl, stored] of Object.entries(storedFiles)) {
  if (!currentFileUrls.has(fileurl)) {
    toDelete.push({
      fileurl,
      filename: stored.filename,
      document_id: stored.document_id,
      namespace,
      action: 'removed'
    });
  }
}

return [{
  json: {
    courseId,
    namespace,
    toIngest,
    toDelete,
    unchanged,
    summary: {
      new: toIngest.filter(f => f.action === 'new').length,
      updated: toIngest.filter(f => f.action === 'updated').length,
      removed: toDelete.length,
      unchanged: unchanged.length
    }
  }
}];

// Handle all deletions inline and return a single item
const fs = require('fs');
const http = require('http');
const { URL } = require('url');
const STATE_FILE = $env.STATE_FILE_PATH || '/home/node/.n8n/moodle-ingest-state.json';
function readState() { try { return JSON.parse(fs.readFileSync(STATE_FILE, 'utf8')); } catch(e) { return { courseFiles: {} }; } }
function writeState(s) { fs.writeFileSync(STATE_FILE, JSON.stringify(s)); }

function httpReq(urlStr, options = {}) {
  return new Promise((resolve, reject) => {
    const url = new URL(urlStr);
    const opts = { hostname: url.hostname, port: url.port || 80, path: url.pathname + url.search, method: options.method || 'GET', headers: options.headers || {} };
    const req = http.request(opts, (res) => { const chunks = []; res.on('data', c => chunks.push(c)); res.on('end', () => resolve({ statusCode: res.statusCode, body: Buffer.concat(chunks) })); });
    req.on('error', reject); req.setTimeout(60000, () => { req.destroy(new Error('Timeout')); });
    if (options.body) req.write(options.body); req.end();
  });
}

const input = $input.first().json;
const state = readState();
const namespace = input.namespace;
const toDelete = input.toDelete || [];

const VEKTRA_API_URL = $env.VEKTRA_API_URL;
const VEKTRA_API_KEY = $env.VEKTRA_API_KEY;

const deleteResults = [];

for (const file of toDelete) {
  if (file.document_id) {
    try {
      const delBody = JSON.stringify({ document_ids: [file.document_id], namespace: file.namespace || namespace });
      await httpReq(`${VEKTRA_API_URL}/api/v1/documents/batch`, {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${VEKTRA_API_KEY}`, 'Content-Length': Buffer.byteLength(delBody) },
        body: delBody,
      });
      deleteResults.push({ filename: file.filename, status: 'deleted' });
    } catch (e) {
      deleteResults.push({ filename: file.filename, status: 'delete_failed', error: e.message });
    }
  }
  if (state.courseFiles && state.courseFiles[namespace]) {
    delete state.courseFiles[namespace][file.fileurl];
  }
}
writeState(state);

return [{ json: { ...input, deleteResults } }];

// Split toIngest array into individual items for the inner loop
const input = $input.first().json;
const toIngest = input.toIngest || [];
const namespace = input.namespace;
const courseId = input.courseId;

// Pipe delete results as sentinel item — no global static data needed
const deleteSentinel = {
  _isDeleteSummary: true,
  namespace,
  courseId,
  deleteResults: (input.deleteResults || []).map(d => ({
    file_name: d.filename, namespace, courseId,
    action: 'removed', status: d.status === 'deleted' ? 'completed' : 'failed',
    error: d.error || null
  }))
};

return [
  { json: deleteSentinel },
  ...toIngest.map(file => ({ json: { ...file, namespace, courseId } }))
];

// Process a single file: download from Moodle, upload to Vektra
// Uses native http module to avoid task runner RPC deadlocks
const http = require('http');
const { URL } = require('url');
const file = $input.first().json;
const namespace = file.namespace;
const courseId = file.courseId;
const uniqueFilename = file.uniqueFilename || `mod${file.moduleId}_${file.filename}`;

const MOODLE_WS_TOKEN = $env.MOODLE_WS_TOKEN;
const VEKTRA_API_URL = $env.VEKTRA_API_URL;
const VEKTRA_API_KEY = $env.VEKTRA_API_KEY;

const fs = require('fs');
const STATE_FILE = $env.STATE_FILE_PATH || '/home/node/.n8n/moodle-ingest-state.json';
function readState() { try { return JSON.parse(fs.readFileSync(STATE_FILE, 'utf8')); } catch(e) { return { courseFiles: {} }; } }
function writeState(s) { fs.writeFileSync(STATE_FILE, JSON.stringify(s)); }

function httpReq(urlStr, options = {}) {
  return new Promise((resolve, reject) => {
    const url = new URL(urlStr);
    const opts = {
      hostname: url.hostname, port: url.port || 80,
      path: url.pathname + url.search, method: options.method || 'GET',
      headers: options.headers || {},
    };
    const req = http.request(opts, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve({
        statusCode: res.statusCode,
        headers: res.headers,
        body: Buffer.concat(chunks),
      }));
    });
    req.on('error', reject);
    req.setTimeout(600000, () => { req.destroy(new Error('Request timeout')); });
    if (options.body) req.write(options.body);
    req.end();
  });
}

try {
  // Step 1: Delete old version if update
  if (file.action === 'updated' && file.old_document_id) {
    const delBody = JSON.stringify({ document_ids: [file.old_document_id], namespace });
    await httpReq(`${VEKTRA_API_URL}/api/v1/documents/batch`, {
      method: 'DELETE',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${VEKTRA_API_KEY}`, 'Content-Length': Buffer.byteLength(delBody) },
      body: delBody,
    });
  }

  // Step 2: Download file from Moodle
  const separator = file.fileurl.includes('?') ? '&' : '?';
  const dlResp = await httpReq(`${file.fileurl}${separator}token=${MOODLE_WS_TOKEN}`);

  if (dlResp.headers['content-type']?.includes('application/json')) {
    return [{ json: {
      file_name: uniqueFilename, namespace, courseId,
      action: file.action, status: 'failed', document_id: null,
      chunk_count: 0, error: 'Download failed: ' + dlResp.body.toString().substring(0, 100)
    }}];
  }

  // Step 3: Upload to Vektra (multipart/form-data)
  const boundary = '----n8nBoundary' + Date.now();
  const header = `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="${uniqueFilename}"\r\nContent-Type: ${file.mimetype}\r\n\r\n`;
  const footer = `\r\n--${boundary}--\r\n`;
  const multipartBody = Buffer.concat([Buffer.from(header), dlResp.body, Buffer.from(footer)]);

  const ingestResp = await httpReq(
    `${VEKTRA_API_URL}/api/v1/ingest?namespace=${encodeURIComponent(namespace)}`,
    {
      method: 'POST',
      headers: {
        'Content-Type': `multipart/form-data; boundary=${boundary}`,
        'Authorization': `Bearer ${VEKTRA_API_KEY}`,
        'Content-Length': multipartBody.length,
      },
      body: multipartBody,
    }
  );

  const body = JSON.parse(ingestResp.body.toString());
  const documentId = body.document_id || null;
  const rawStatus = body.status || (ingestResp.statusCode >= 200 && ingestResp.statusCode < 300 ? 'completed' : 'failed');
  const status = (['new', 'exists', 'alias'].includes(rawStatus) && documentId) ? 'completed' : rawStatus;
  const chunkCount = body.chunk_count || 0;
  const error = body.detail?.error?.message || body.error?.message || null;

  // Step 4: Update state on success (file-based persistence)
  if (documentId && status === 'completed') {
    const state = readState();
    if (!state.courseFiles) state.courseFiles = {};
    if (!state.courseFiles[namespace]) state.courseFiles[namespace] = {};
    state.courseFiles[namespace][file.fileurl] = {
      timemodified: file.timemodified,
      document_id: documentId,
      filename: uniqueFilename,
      last_synced: new Date().toISOString()
    };
    writeState(state);
  }

  return [{ json: {
    file_name: uniqueFilename, namespace, courseId,
    action: file.action, status, document_id: documentId,
    chunk_count: chunkCount, error
  }}];
} catch (e) {
  return [{ json: {
    file_name: uniqueFilename, namespace, courseId,
    action: file.action, status: 'failed', document_id: null,
    chunk_count: 0, error: e.message?.substring(0, 200)
  }}];
}

// Collapse all file results from inner loop into 1 item
// This ensures Loop Courses advances by exactly 1
const items = $input.all();
const results = items.map(item => item.json);

// Separate sentinel (delete results) from real file results
const sentinel = results.find(r => r._isDeleteSummary);
const deleteItems = sentinel?.deleteResults || [];
const fileResults = results.filter(r => !r._isDeleteSummary);

const allResults = [...deleteItems, ...fileResults];
return [{ json: { courseResults: allResults, resultCount: allResults.length } }];

// No files to ingest — return single item with unchanged and deletion info
const input = $input.first().json;
const unchangedFiles = (input.unchanged || []).map(f => ({
  file_name: f.uniqueFilename || f.filename,
  namespace: input.namespace,
  courseId: input.courseId,
  action: 'unchanged',
  status: 'skipped'
}));
const deleteItems = (input.deleteResults || []).map(d => ({
  file_name: d.filename,
  namespace: input.namespace,
  courseId: input.courseId,
  action: 'removed',
  status: d.status === 'deleted' ? 'completed' : 'failed',
  error: d.error || null
}));
const allResults = [...deleteItems, ...unchangedFiles];
return [{ json: { courseResults: allResults, resultCount: allResults.length } }];

// Aggregate results from all courses
const items = $input.all();

let totalNew = 0, totalUpdated = 0, totalRemoved = 0;
let totalUnchanged = 0, totalFailed = 0;
const details = [];

for (const item of items) {
  const results = item.json.courseResults || [item.json];
  for (const d of results) {
    if (d.action === 'new' && (d.status === 'completed' || d.status === 'new')) totalNew++;
    else if (d.action === 'updated' && (d.status === 'completed' || d.status === 'new')) totalUpdated++;
    else if (d.action === 'removed') totalRemoved++;
    else if (d.action === 'unchanged' || d.status === 'skipped') totalUnchanged++;
    else if (d.status === 'failed' || d.status === 'timeout') totalFailed++;

    if (d.file_name || d.filename) {
      details.push({
        file: d.file_name || d.filename,
        namespace: d.namespace,
        action: d.action || 'unknown',
        status: d.status || 'n/a',
        document_id: d.document_id || null,
        error: d.error || null
      });
    }
  }
}

const summary = `Sync complete: ${totalNew} new, ${totalUpdated} updated, ${totalRemoved} removed, ${totalUnchanged} unchanged, ${totalFailed} failed`;
console.log(summary);

return [{
  json: {
    summary,
    totals: { new: totalNew, updated: totalUpdated, removed: totalRemoved, unchanged: totalUnchanged, failed: totalFailed },
    details
  }
}];
